st_before_fix:
FUNCTION_BLOCK FB_SimpleRepeat
VAR_INPUT
INPUT_VAR1 : INT := 2;
INPUT_COUNTER : INT := 4;
END_VAR

VAR_OUTPUT
OUTPUT_VAR1 : INT;
END_VAR

VAR
COUNTER : INT;
END_VAR


OUTPUT_VAR1 := INPUT_VAR1;
COUNTER := INPUT_COUNTER;
WHILE COUNTER > 0 DO
OUTPUT_VAR1 := OUTPUT_VAR1 * 2;
COUNTER := COUNTER - 1;
END_WHILE
END_FUNCTION_BLOCK
